INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("ヤマト", "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 2.1, "2030/01/01 14:59:59", 0.0, 100, 3001100, 1, 130011, -416.5, 3001, 2, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("ヤマト", "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 5.68, "2030/01/01 14:59:59", 0.0, 101, 3001101, 4, 130011, -416.5, 3001, 2, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("ヤマト", "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 0.0, "2030/01/01 14:59:59", 0.0, 102, 3001102, 1, 130011, -416.5, 3001, 1, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 0.0, "2030/01/01 14:59:59", 0.0, 100, 3002100, 1, 130211, -416.5, 3002, 1, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 0.0, "2030/01/01 14:59:59", 0.0, 101, 3002101, 1, 130211, -416.5, 3002, 1, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 8.53, "2030/01/01 14:59:59", 0.0, 102, 3002102, 5, 130211, -416.5, 3002, 2, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 5.67, "2030/01/01 14:59:59", 0.0, 103, 3002103, 7, 130211, -416.5, 3002, 1, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 0.0, "2030/01/01 14:59:59", 0.0, 104, 3002104, 1, 130211, -416.5, 3002, 1, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 0.0, "2030/01/01 14:59:59", 0.0, 300, 3002300, 3, 130211, -416.5, 3004, 3, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 0.0, "2030/01/01 14:59:59", 0.0, 301, 3002400, 7, 130211, -416.5, 3005, 7, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 4.4, "2030/01/01 14:59:59", 0.0, 200, 3003200, 2, 130211, -416.5, 3003, 1, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 0.0, "2030/01/01 14:59:59", 0.0, 201, 3003201, 7, 130211, -416.5, 3003, 7, "2024/10/31 12:00:00");
INSERT INTO `v1_08b462e73ee8b6194ab473db71d1621a861f0e32f35b77f66a32089ff8bafa52` VALUES ("フブキ", "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 5.6, "2030/01/01 14:59:59", 0.0, 202, 3003202, 1, 130211, -416.5, 3003, 2, "2024/10/31 12:00:00");
